Include %occStatus

Class Document.Entry Extends %Persistent
{

    Property Title As %String;
    Property AttachmentId As %String;

    /// Get the filename of the linked attachment
    Method GetAttachmentName() As %String
    {
        // BUGGY: No check if attachment still exists
        Set att = ##class(Document.Attachment).%OpenId(..AttachmentId)
        Return att.FileName  // <INVALID OREF> if attachment was deleted
    }

}

Class Document.Attachment Extends %Persistent
{

    Property FileName As %String;
    Property SizeKB As %Integer;

}

