Class TestDocumentEntry Extends %RegisteredObject
{

    ClassMethod TestGetAttachmentName()
    {
        Do ##class(Document.Entry).%KillExtent()
        Do ##class(Document.Attachment).%KillExtent()

        // Create attachment and entry
        Set att = ##class(Document.Attachment).%New()
        Set att.FileName = "report.pdf"
        Do att.%Save()

        Set entry = ##class(Document.Entry).%New()
        Set entry.Title = "Q4 Report"
        Set entry.AttachmentId = att.%Id()
        Do entry.%Save()

        // Should return filename when attachment exists
        Set name = entry.GetAttachmentName()
        If (name '= "report.pdf") {
            Throw ##class(%Exception.General).%New("Expected report.pdf, got "_name)
        }

        // Delete attachment then re-open entry
        Do ##class(Document.Attachment).%DeleteId(att.%Id())
        Set entry2 = ##class(Document.Entry).%OpenId(entry.%Id())

        // Should return empty string, not throw <INVALID OREF>
        Set name = entry2.GetAttachmentName()
        If (name '= "") {
            Throw ##class(%Exception.General).%New("Deleted attachment should return empty string, got "_name)
        }
    }

}
